<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BorrowService; $q=$_GET['q']??''; $status=$_GET['status']??'borrowing'; $rows=(new BorrowService())->all($q,$status); $title='Quản lý mượn tài liệu'; include ROOT_PATH.'/includes/header.php'; ?><div class="d-flex justify-content-between mb-3"><h1 class="h3">Phiếu mượn tài liệu</h1><a class="btn btn-primary" href="create.php">Tạo phiếu mượn</a></div><form class="row mb-3"><div class="col-md-7"><input name="q" class="form-control" placeholder="Tìm tài liệu, thành viên, mã sinh viên..." value="<?= e($q) ?>"></div><div class="col-md-3"><select name="status" class="form-select"><option value="borrowing" <?= selected($status,'borrowing') ?>>Đang mượn</option><option value="overdue" <?= selected($status,'overdue') ?>>Quá hạn</option><option value="all" <?= selected($status,'all') ?>>Tất cả</option></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Lọc</button></div></form><table class="table table-bordered table-striped"><tr><th>Thành viên</th><th>Loại</th><th>Tài liệu</th><th>Ngày mượn</th><th>Hạn trả</th><th>Trạng thái</th><th width="260">Thao tác</th></tr><?php foreach($rows as $r): $over=$r['status']==='borrowing'&&strtotime($r['due_date'])<strtotime(date('Y-m-d')); ?><tr><td><?= e($r['member_name']) ?></td><td><span class="badge bg-<?= item_badge_class($r['item_type']) ?>"><?= item_type_vi($r['item_type']) ?></span></td><td><?= e($r['item_title']) ?></td><td><?= date_vi($r['borrow_date']) ?></td><td><?= date_vi($r['due_date']) ?></td><td><?php if($r['status']==='returned') echo '<span class="badge bg-success">Đã trả</span>'; elseif($over) echo '<span class="badge bg-danger">Quá hạn</span>'; else echo '<span class="badge bg-warning text-dark">Đang mượn</span>'; ?></td><td><div class="action-buttons"><a class="btn btn-sm btn-info" href="detail.php?id=<?= $r['id'] ?>">Xem</a><?php if($r['status']==='borrowing'): ?><a class="btn btn-sm btn-warning" href="edit.php?id=<?= $r['id'] ?>">Sửa</a><a data-confirm="Xóa phiếu mượn này và hoàn lại số lượng tài liệu?" class="btn btn-sm btn-danger" href="delete.php?id=<?= $r['id'] ?>">Xóa</a><a class="btn btn-sm btn-success" href="../returns/create.php?borrow_id=<?= $r['id'] ?>">Trả</a><?php endif; ?></div></td></tr><?php endforeach; ?></table><?php include ROOT_PATH.'/includes/footer.php'; ?>
